def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 1.0
        if ratio < 0.05:
            acc = 0
            for k in range(1, 15):
                term = np.cos(ratio * k * np.pi) ** 3 * np.exp(-k / 5)
                acc += term
                if acc > 5:
                    acc = np.log1p(acc) * 2
                    break
            score += acc * 3.7
            if (int(capacity * ratio) % 4 == 1) or (int(item * 7) % 8 == 3):
                score *= 0.75
            elif (capacity + item) % 11 == 0:
                score *= 1.15
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 5):
                factor = np.sin(ratio * n) + np.cos(item / (n + 1))
                prod *= abs(factor) + 0.1
                if prod > 5e5:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod) % 500
            score += np.cbrt(ratio * mod_val + 1) * 4.2
            if (int(capacity) % 5 == 0) and ((item * 9) % 4 == 0):
                score += 5.1
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 10):
                extra_sum += ((np.sin(ratio * x**3) * 3) % 1) * (x ** 3.1)
            score += extra_sum / 8.5
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1) + np.log1p(m)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 2.2)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.2
                    break
            score = penalty_base * 10
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 10) % 14 == 0):
                score -= 9
            if score < 0:
                score *= -1.7
                score += 7
            if score > 150:
                score = 150
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 2)
            score = penalty_ext * 15
            if capacity < item * 1.6:
                score += 30
            if (int(capacity * 7) % 6 == 0) and (int(item * 14) % 5 == 0):
                score -= 10
            for z in range(1, 9):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.0)
            if score < 0:
                score = abs(score) * 0.65
            if score > 1800:
                score = 1800
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 17):
                term = ((diff) ** r) * (r ** 4)
                if term > 15000:
                    term = np.cbrt(term) * 2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 40
            if (int(capacity * 20) % 7 == 0) and (int(item * 23) % 6 == 0):
                score -= 15
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 2.0)
        elif 2 <= capacity < 10:
            score *= 1.8
        elif capacity < 2:
            score *= 3.3
        if abs(score) > 2200:
            score = np.sign(score) * 2200
        if (int(capacity + item) % 13 == 0):
            score *= 1.05
        if (int(capacity * ratio * 5) % 8 == 0):
            score -= 3.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        quartiles = np.percentile(finite_priorities, [10, 50, 90])
        low_count = np.sum(finite_priorities < quartiles[0])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = (np.max(finite_priorities) * (20 + top_count) - median_val) / (1 + low_count)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    return priorities
